document.addEventListener("DOMContentLoaded",function(){function e(e){e.wrapperEl&&e.wrapperEl.removeAttribute("role"),e.slides.forEach(e=>{e.removeAttribute("role")})}new Swiper(".slider_component",{loop:!0,grabCursor:!0,slideToClickedSlide:!0,keyboard:{enabled:!0,onlyInViewport:!0},pagination:{el:".slider_pagination",clickable:!0,dynamicBullets:!0,dynamicMainBullets:1},breakpoints:{992:{slidesPerView:3,spaceBetween:86},480:{slidesPerView:2,spaceBetween:32},0:{slidesPerView:1,spaceBetween:0}},on:{init:function(){e(this)},slideChange:function(){e(this)}}})});